final:
module RefModule(
    input clk,
    input [3:0] D,
    input SI,
    output reg SO
);reg [3:0] obf_reg_data;

    always @(posedge clk) begin
        if (SI) begin
            obf_reg_data <= {obf_reg_data[2:0], SI};
        end else begin
            obf_reg_data <= D;
        end
    end

    assign SO = obf_reg_data[0];

endmodule
